-- Router primary schema baseline.
-- Generated by squashing the prior migration chain into the final public schema.

CREATE FUNCTION public.update_updated_at_column() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$;


SET default_tablespace = '';

SET default_table_access_method = heap;


CREATE TABLE public.custody_vaults (
    id uuid NOT NULL,
    order_id uuid,
    role text NOT NULL,
    visibility text NOT NULL,
    chain_id text NOT NULL,
    asset_id text,
    address text NOT NULL,
    control_type text NOT NULL,
    derivation_salt bytea,
    signer_ref text,
    status text NOT NULL,
    metadata_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone NOT NULL,
    updated_at timestamp with time zone NOT NULL,
    CONSTRAINT custody_vaults_address_not_empty CHECK ((address <> ''::text)),
    CONSTRAINT custody_vaults_asset_id_not_empty CHECK (((asset_id IS NULL) OR (asset_id <> ''::text))),
    CONSTRAINT custody_vaults_chain_id_not_empty CHECK ((chain_id <> ''::text)),
    CONSTRAINT custody_vaults_control_type_check CHECK ((control_type = ANY (ARRAY['router_derived_key'::text, 'paymaster_wallet'::text, 'hyperliquid_master_signer'::text, 'external_user'::text, 'watch_only'::text]))),
    CONSTRAINT custody_vaults_derivation_salt_len CHECK (((derivation_salt IS NULL) OR (octet_length(derivation_salt) = 32))),
    CONSTRAINT custody_vaults_metadata_object CHECK ((jsonb_typeof(metadata_json) = 'object'::text)),
    CONSTRAINT custody_vaults_role_check CHECK ((role = ANY (ARRAY['source_deposit'::text, 'destination_execution'::text, 'hyperliquid_spot'::text]))),
    CONSTRAINT custody_vaults_signer_ref_not_empty CHECK (((signer_ref IS NULL) OR (signer_ref <> ''::text))),
    CONSTRAINT custody_vaults_status_check CHECK ((status = ANY (ARRAY['planned'::text, 'active'::text, 'released'::text, 'failed'::text]))),
    CONSTRAINT custody_vaults_visibility_check CHECK ((visibility = ANY (ARRAY['user_facing'::text, 'internal'::text, 'watch_only'::text])))
);



CREATE TABLE public.deposit_vault_funding_hints (
    id uuid NOT NULL,
    vault_id uuid NOT NULL,
    source text NOT NULL,
    hint_kind text NOT NULL,
    evidence_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    status text NOT NULL,
    idempotency_key text,
    error_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    claimed_at timestamp with time zone,
    processed_at timestamp with time zone,
    created_at timestamp with time zone NOT NULL,
    updated_at timestamp with time zone NOT NULL,
    CONSTRAINT deposit_vault_funding_hints_error_object CHECK ((jsonb_typeof(error_json) = 'object'::text)),
    CONSTRAINT deposit_vault_funding_hints_evidence_object CHECK ((jsonb_typeof(evidence_json) = 'object'::text)),
    CONSTRAINT deposit_vault_funding_hints_idempotency_key_not_empty CHECK (((idempotency_key IS NULL) OR (idempotency_key <> ''::text))),
    CONSTRAINT deposit_vault_funding_hints_kind_check CHECK ((hint_kind = 'possible_progress'::text)),
    CONSTRAINT deposit_vault_funding_hints_source_not_empty CHECK ((source <> ''::text)),
    CONSTRAINT deposit_vault_funding_hints_status_check CHECK ((status = ANY (ARRAY['pending'::text, 'processing'::text, 'processed'::text, 'ignored'::text, 'failed'::text])))
);



CREATE TABLE public.deposit_vaults (
    id uuid NOT NULL,
    action jsonb NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    recovery_address character varying(255) NOT NULL,
    cancellation_commitment bytea NOT NULL,
    cancel_after timestamp with time zone NOT NULL,
    status text NOT NULL,
    refund_requested_at timestamp with time zone,
    refunded_at timestamp with time zone,
    refund_tx_hash text,
    last_refund_error text,
    created_at timestamp with time zone NOT NULL,
    updated_at timestamp with time zone NOT NULL,
    refund_attempt_count integer DEFAULT 0 NOT NULL,
    last_refund_attempt_at timestamp with time zone,
    refund_next_attempt_at timestamp with time zone,
    refund_claimed_by text,
    refund_claimed_until timestamp with time zone,
    CONSTRAINT deposit_vault_cancellation_commitment_len CHECK ((octet_length(cancellation_commitment) = 32)),
    CONSTRAINT deposit_vault_status_check CHECK ((status = ANY (ARRAY['pending_funding'::text, 'funded'::text, 'executing'::text, 'completed'::text, 'refund_required'::text, 'refunding'::text, 'refunded'::text, 'refund_manual_intervention_required'::text])))
);



CREATE TABLE public.market_order_actions (
    order_id uuid NOT NULL,
    order_kind text NOT NULL,
    amount_in text,
    min_amount_out text,
    amount_out text,
    max_amount_in text,
    created_at timestamp with time zone NOT NULL,
    updated_at timestamp with time zone NOT NULL,
    slippage_bps bigint NOT NULL,
    CONSTRAINT market_order_actions_amount_in_digits CHECK (((amount_in IS NULL) OR (amount_in ~ '^[0-9]+$'::text))),
    CONSTRAINT market_order_actions_amount_out_digits CHECK (((amount_out IS NULL) OR (amount_out ~ '^[0-9]+$'::text))),
    CONSTRAINT market_order_actions_max_amount_in_digits CHECK (((max_amount_in IS NULL) OR (max_amount_in ~ '^[0-9]+$'::text))),
    CONSTRAINT market_order_actions_min_amount_out_digits CHECK (((min_amount_out IS NULL) OR (min_amount_out ~ '^[0-9]+$'::text))),
    CONSTRAINT market_order_actions_order_kind_check CHECK ((order_kind = ANY (ARRAY['exact_in'::text, 'exact_out'::text]))),
    CONSTRAINT market_order_actions_shape_check CHECK ((((order_kind = 'exact_in'::text) AND (amount_in IS NOT NULL) AND (min_amount_out IS NOT NULL) AND (amount_out IS NULL) AND (max_amount_in IS NULL)) OR ((order_kind = 'exact_out'::text) AND (amount_in IS NULL) AND (min_amount_out IS NULL) AND (amount_out IS NOT NULL) AND (max_amount_in IS NOT NULL)))),
    CONSTRAINT market_order_actions_slippage_bps_check CHECK (((slippage_bps >= 0) AND (slippage_bps <= 10000)))
);



CREATE TABLE public.market_order_quotes (
    id uuid NOT NULL,
    order_id uuid,
    provider_id text NOT NULL,
    order_kind text NOT NULL,
    amount_in text NOT NULL,
    amount_out text NOT NULL,
    min_amount_out text,
    max_amount_in text,
    provider_quote jsonb DEFAULT '{}'::jsonb NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone NOT NULL,
    source_chain_id text NOT NULL,
    source_asset_id text NOT NULL,
    destination_chain_id text NOT NULL,
    destination_asset_id text NOT NULL,
    recipient_address text NOT NULL,
    slippage_bps bigint NOT NULL,
    CONSTRAINT market_order_quotes_amount_in_digits CHECK ((amount_in ~ '^[0-9]+$'::text)),
    CONSTRAINT market_order_quotes_amount_out_digits CHECK ((amount_out ~ '^[0-9]+$'::text)),
    CONSTRAINT market_order_quotes_destination_asset_not_empty CHECK ((destination_asset_id <> ''::text)),
    CONSTRAINT market_order_quotes_destination_chain_not_empty CHECK ((destination_chain_id <> ''::text)),
    CONSTRAINT market_order_quotes_max_amount_in_digits CHECK (((max_amount_in IS NULL) OR (max_amount_in ~ '^[0-9]+$'::text))),
    CONSTRAINT market_order_quotes_min_amount_out_digits CHECK (((min_amount_out IS NULL) OR (min_amount_out ~ '^[0-9]+$'::text))),
    CONSTRAINT market_order_quotes_order_kind_check CHECK ((order_kind = ANY (ARRAY['exact_in'::text, 'exact_out'::text]))),
    CONSTRAINT market_order_quotes_provider_id_not_empty CHECK ((provider_id <> ''::text)),
    CONSTRAINT market_order_quotes_recipient_address_not_empty CHECK ((recipient_address <> ''::text)),
    CONSTRAINT market_order_quotes_slippage_bps_check CHECK (((slippage_bps >= 0) AND (slippage_bps <= 10000))),
    CONSTRAINT market_order_quotes_source_asset_not_empty CHECK ((source_asset_id <> ''::text)),
    CONSTRAINT market_order_quotes_source_chain_not_empty CHECK ((source_chain_id <> ''::text))
);



CREATE TABLE public.order_execution_attempts (
    id uuid NOT NULL,
    order_id uuid NOT NULL,
    attempt_index integer NOT NULL,
    attempt_kind text NOT NULL,
    status text NOT NULL,
    trigger_step_id uuid,
    trigger_provider_operation_id uuid,
    failure_reason_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    input_custody_snapshot_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone NOT NULL,
    updated_at timestamp with time zone NOT NULL,
    CONSTRAINT order_execution_attempts_attempt_index_positive CHECK ((attempt_index > 0)),
    CONSTRAINT order_execution_attempts_attempt_kind_check CHECK ((attempt_kind = ANY (ARRAY['primary_execution'::text, 'retry_execution'::text, 'refund_recovery'::text]))),
    CONSTRAINT order_execution_attempts_failure_reason_object CHECK ((jsonb_typeof(failure_reason_json) = 'object'::text)),
    CONSTRAINT order_execution_attempts_input_custody_snapshot_object CHECK ((jsonb_typeof(input_custody_snapshot_json) = 'object'::text)),
    CONSTRAINT order_execution_attempts_status_check CHECK ((status = ANY (ARRAY['planning'::text, 'active'::text, 'completed'::text, 'failed'::text, 'refund_required'::text, 'manual_intervention_required'::text])))
);



CREATE TABLE public.order_execution_steps (
    id uuid NOT NULL,
    order_id uuid NOT NULL,
    transition_decl_id text,
    step_index integer NOT NULL,
    step_type text NOT NULL,
    provider text NOT NULL,
    status text NOT NULL,
    input_chain_id text,
    input_asset_id text,
    output_chain_id text,
    output_asset_id text,
    amount_in text,
    min_amount_out text,
    tx_hash text,
    provider_ref text,
    idempotency_key text,
    attempt_count integer DEFAULT 0 NOT NULL,
    next_attempt_at timestamp with time zone,
    started_at timestamp with time zone,
    completed_at timestamp with time zone,
    details_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    request_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    response_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    error_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone NOT NULL,
    updated_at timestamp with time zone NOT NULL,
    execution_attempt_id uuid,
    CONSTRAINT order_execution_steps_amount_in_digits CHECK (((amount_in IS NULL) OR (amount_in ~ '^[0-9]+$'::text))),
    CONSTRAINT order_execution_steps_attempt_count_nonnegative CHECK ((attempt_count >= 0)),
    CONSTRAINT order_execution_steps_details_object CHECK ((jsonb_typeof(details_json) = 'object'::text)),
    CONSTRAINT order_execution_steps_error_object CHECK ((jsonb_typeof(error_json) = 'object'::text)),
    CONSTRAINT order_execution_steps_idempotency_key_not_empty CHECK (((idempotency_key IS NULL) OR (idempotency_key <> ''::text))),
    CONSTRAINT order_execution_steps_input_asset_pair CHECK ((((input_chain_id IS NULL) AND (input_asset_id IS NULL)) OR ((input_chain_id IS NOT NULL) AND (input_asset_id IS NOT NULL)))),
    CONSTRAINT order_execution_steps_lifecycle_timestamps CHECK (((completed_at IS NULL) OR (started_at IS NULL) OR (completed_at >= started_at))),
    CONSTRAINT order_execution_steps_min_amount_out_digits CHECK (((min_amount_out IS NULL) OR (min_amount_out ~ '^[0-9]+$'::text))),
    CONSTRAINT order_execution_steps_output_asset_pair CHECK ((((output_chain_id IS NULL) AND (output_asset_id IS NULL)) OR ((output_chain_id IS NOT NULL) AND (output_asset_id IS NOT NULL)))),
    CONSTRAINT order_execution_steps_provider_not_empty CHECK ((provider <> ''::text)),
    CONSTRAINT order_execution_steps_provider_ref_not_empty CHECK (((provider_ref IS NULL) OR (provider_ref <> ''::text))),
    CONSTRAINT order_execution_steps_request_object CHECK ((jsonb_typeof(request_json) = 'object'::text)),
    CONSTRAINT order_execution_steps_response_object CHECK ((jsonb_typeof(response_json) = 'object'::text)),
    CONSTRAINT order_execution_steps_status_check CHECK ((status = ANY (ARRAY['planned'::text, 'waiting'::text, 'ready'::text, 'running'::text, 'completed'::text, 'failed'::text, 'skipped'::text, 'cancelled'::text]))),
    CONSTRAINT order_execution_steps_step_index_nonnegative CHECK ((step_index >= 0)),
    CONSTRAINT order_execution_steps_step_type_check CHECK ((step_type = ANY (ARRAY['wait_for_deposit'::text, 'across_bridge'::text, 'cctp_burn'::text, 'cctp_receive'::text, 'unit_deposit'::text, 'unit_withdrawal'::text, 'hyperliquid_trade'::text, 'hyperliquid_bridge_deposit'::text, 'universal_router_swap'::text, 'refund'::text]))),
    CONSTRAINT order_execution_steps_transition_decl_id_not_empty CHECK (((transition_decl_id IS NULL) OR (transition_decl_id <> ''::text))),
    CONSTRAINT order_execution_steps_tx_hash_not_empty CHECK (((tx_hash IS NULL) OR (tx_hash <> ''::text)))
);



