CREATE UNIQUE INDEX idx_custody_vaults_chain_address ON public.custody_vaults USING btree (chain_id, address);



CREATE INDEX idx_custody_vaults_order_id ON public.custody_vaults USING btree (order_id) WHERE (order_id IS NOT NULL);



